  ('optician-moex-00139', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何種隱形眼鏡鏡片特性並非相對較容易產生角膜皺褶（cornealwrinkle）之因素？', '["超薄", "高含水量", "高彈性度（elasticity）", "弧度對於角膜較陡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00140', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於配戴隱形眼鏡產生的角膜新生血管（neovascularization），下列何者錯誤？', '["新生血管的定義為：微血管形成在原本無血管的角膜區域", "主要是因為角膜缺氧所造成", "常見於長時間戴矽水膠（siliconehydrogel）材質的軟式隱形眼鏡的患者", "新生血管在停戴隱形眼鏡後通常會改善，但仍可能會產生幽靈血管（ghostvessels）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00141', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '軟式隱形眼鏡引起的乳突結膜炎，若引發嚴重的症狀，選擇停戴會有比較好的預後。停戴後，結膜乳突何 時會消失？', '["停戴後2至3天", "停戴後1至2週", "停戴後數週至半年", "不會消失"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00142', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式高透氧鏡片保存盒（lenscase）的敘述，下列何者錯誤？', '["鏡片保存盒是造成眼部感染的常見感染源", "最好至少每1～3個月更換新的鏡片保存盒", "挑選保存盒時，內面完全平滑、沒有隆起線為首選", "每天應該清潔保存盒內層至少5秒，倒置陰乾更佳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00143', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關有乾眼症的人欲配戴隱形眼鏡的注意事項，下列何者錯誤？', '["配戴硬式隱形眼鏡比較會有乾眼的症狀", "罹患角膜破皮的病人，可以配戴治療型隱形眼鏡來幫助角膜癒合，但須遵照醫師吩咐按時回診", "建議不要配戴高含水量水膠（hydrogel）隱形眼鏡", "建議配戴矽水膠（siliconehydrogel）隱形眼鏡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00144', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '矽水凝膠鏡片（siliconehydrogellens）可以減低以下那種情形發生的機會？①隱形眼鏡引起的乳突結膜炎', '["角膜新生血管NV", "角膜皺摺和條紋folds and striae", "角膜水腫corneal oedema  ⑤角膜上 皮層弧狀角膜損害SEAL", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 42, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00145', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於上部角膜上皮弓形缺損（superiorepithelialarcuatelesions,SEALs）下列何者正確？', '["和角膜缺氧相關", "戴水膠（hydrogel）材質隱形眼鏡較易產生", "可暫時先停戴隱形眼鏡並使用眼睛潤滑劑（ocularlubricants）改善症狀", "角膜產生此病變代表病患不適合使用此種形式的隱形眼鏡，一定要更換隱形眼鏡材質才可以"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00146', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '黏液球（mucinball）與下列何種隱形眼鏡最有關聯？', '["水膠鏡片", "矽水膠鏡片", "不透氧硬式鏡片（PMMA）", "透氧硬式鏡片（RGP）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00147', 'optician', 'optician-moex-114-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '非球面老花隱形眼鏡要驗配成功，需要注意的事項，下列何者較不重要？', '["瞳孔大小會影響視覺品質，如果瞳孔太小，配戴中心視近（center-near）設計的隱形眼鏡，會影響看遠視力", "淚液品質的評估，淚膜裂解時間（tearfilmbreakuptime,TBUT）如果小於5秒，就不適合配戴隱形眼鏡", "中心定位很重要，下眼瞼的位置不可低於輪部下緣1.5mm", "病人想要配戴老花隱形眼鏡的動機是一項重要的因素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:26+00:00", "source_pdf_sha1": "b70d36ef6657", "answer_pdf_sha1": "5101fd87d88e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "110", "s": "0908", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
